1	type Cell = [number, number];
2	
3	const cellKey = ([row, col]: Cell): string => `${row},${col}`;
4	
5	const parseKey = (key: string): Cell => {
6	  const [r, c] = key.split(",").map(Number);
7	  return [r, c];
8	};
9	
10	const neighborsOf = ([row, col]: Cell): Cell[] => {
11	  const result: Cell[] = [];
12	  for (let dr = -1; dr <= 1; dr++) {
13	    for (let dc = -1; dc <= 1; dc++) {
14	      if (dr === 0 && dc === 0) continue;
15	      result.push([row + dr, col + dc]);
16	    }
17	  }
18	  return result;
19	};
20	
21	const countLiveNeighbors = (cell: Cell, liveSet: Set<string>): number =>
22	  neighborsOf(cell).filter((neighbor) => liveSet.has(cellKey(neighbor))).length;
23	
24	const deadNeighbors = (liveCells: Cell[], liveSet: Set<string>): Cell[] => {
25	  const candidates = new Set<string>();
26	  for (const cell of liveCells) {
27	    for (const neighbor of neighborsOf(cell)) {
28	      const key = cellKey(neighbor);
29	      if (!liveSet.has(key)) candidates.add(key);
30	    }
31	  }
32	  return [...candidates].map(parseKey);
33	};
34	
35	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
36	  const liveSet = new Set(liveCells.map(cellKey));
37	  const survivors = liveCells.filter((cell) => {
38	    const neighbors = countLiveNeighbors(cell, liveSet);
39	    return neighbors === 2 || neighbors === 3;
40	  });
41	  const births = deadNeighbors(liveCells, liveSet).filter(
42	    (cell) => countLiveNeighbors(cell, liveSet) === 3
43	  );
44	  return [...survivors, ...births];
45	};
