32	  });
33	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
34	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
35	    expect(result).toContainEqual([1, 1]);
36	  });
